  struct
    type nonrec t =
      {
      dnsConfigurationList: DnsConfigurationList.t option
        [@ocaml.doc
          "The list of domain names, their statuses, and a description of each status."]}
    type nonrec error =
      [ `AccessDenied of AccessDenied.t 
      | `EntityNotFound of EntityNotFound.t 
      | `InvalidArgument of InvalidArgument.t 
      | `Unknown_operation_error of (string * string option) ]
    let make ?dnsConfigurationList = fun () -> { dnsConfigurationList }
    let error_of_json name json =
      match name with
      | "AccessDenied" -> `AccessDenied (AccessDenied.of_json json)
      | "EntityNotFound" -> `EntityNotFound (EntityNotFound.of_json json)
      | "InvalidArgument" -> `InvalidArgument (InvalidArgument.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "AccessDenied" -> `AccessDenied (AccessDenied.of_xml xml)
      | "EntityNotFound" -> `EntityNotFound (EntityNotFound.of_xml xml)
      | "InvalidArgument" -> `InvalidArgument (InvalidArgument.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `AccessDenied e ->
          `Assoc
            [("error", (`String "AccessDenied"));
            ("details", (AccessDenied.to_json e))]
      | `EntityNotFound e ->
          `Assoc
            [("error", (`String "EntityNotFound"));
            ("details", (EntityNotFound.to_json e))]
      | `InvalidArgument e ->
          `Assoc
            [("error", (`String "InvalidArgument"));
            ("details", (InvalidArgument.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
    let to_value x =
      structure_to_value
        [("DnsConfigurationList",
           (Option.map x.dnsConfigurationList
              ~f:DnsConfigurationList.to_value))]
