  end[@@ocaml.doc
       "Copies the staging distribution's configuration to its corresponding primary distribution. The primary distribution retains its Aliases (also known as alternate domain names or CNAMEs) and ContinuousDeploymentPolicyId value, but otherwise its configuration is overwritten to match the staging distribution. You can use this operation in a continuous deployment workflow after you have tested configuration changes on the staging distribution. After using a continuous deployment policy to move a portion of your domain name's traffic to the staging distribution and verifying that it works as intended, you can use this operation to copy the staging distribution's configuration to the primary distribution. This action will disable the continuous deployment policy and move your domain's traffic back to the primary distribution. This API operation requires the following IAM permissions: GetDistribution UpdateDistribution"]
module UpdateDistributionWithStagingConfigRequest =
  struct
    type nonrec t =
      {
      id: String_.t
        [@ocaml.doc
          "The identifier of the primary distribution to which you are copying a staging distribution's configuration."];
      stagingDistributionId: String_.t option
        [@ocaml.doc
          "The identifier of the staging distribution whose configuration you are copying to the primary distribution."];
      ifMatch: String_.t option
        [@ocaml.doc
          "The current versions (ETag values) of both primary and staging distributions. Provide these in the following format: <primary ETag>, <staging ETag>"]}
    let context_ = "UpdateDistributionWithStagingConfigRequest"
    let make ?stagingDistributionId =
      fun ?ifMatch ->
        fun ~id -> fun () -> { stagingDistributionId; ifMatch; id }
    let to_value x =
      structure_to_value
        [("Id", (Some (String_.to_value x.id)));
        ("StagingDistributionId",
          (Option.map x.stagingDistributionId ~f:String_.to_value));
        ("If-Match", (Option.map x.ifMatch ~f:String_.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let ifMatch =
        (Option.map ~f:String_.of_xml) (Xml.child xml_arg0 "If-Match") in
      let stagingDistributionId =
        (Option.map ~f:String_.of_xml)
          (Xml.child xml_arg0 "StagingDistributionId") in
      let id = String_.of_xml (Xml.child_exn ~context:context_ xml_arg0 "Id") in
      make ?ifMatch ?stagingDistributionId ~id ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
      let ifMatch = field_map json__ "IfMatch" String_.of_json in
      let stagingDistributionId =
        field_map json__ "StagingDistributionId" String_.of_json in
      let id = field_map_exn json__ "Id" String_.of_json in
      make ?ifMatch ?stagingDistributionId ~id ()
    let to_json v = composed_to_json to_value v
  end[@@ocaml.doc
       "Copies the staging distribution's configuration to its corresponding primary distribution. The primary distribution retains its Aliases (also known as alternate domain names or CNAMEs) and ContinuousDeploymentPolicyId value, but otherwise its configuration is overwritten to match the staging distribution. You can use this operation in a continuous deployment workflow after you have tested configuration changes on the staging distribution. After using a continuous deployment policy to move a portion of your domain name's traffic to the staging distribution and verifying that it works as intended, you can use this operation to copy the staging distribution's configuration to the primary distribution. This action will disable the continuous deployment policy and move your domain's traffic back to the primary distribution. This API operation requires the following IAM permissions: GetDistribution UpdateDistribution"]
module UpdateDistributionTenantResult =
  struct
    type nonrec t =
      {
      distributionTenant: DistributionTenant.t option
        [@ocaml.doc "The distribution tenant that you're updating."];
      eTag: String_.t option
        [@ocaml.doc "The current version of the distribution tenant."]}
    type nonrec error =
      [ `AccessDenied of AccessDenied.t 
      | `CNAMEAlreadyExists of CNAMEAlreadyExists.t 
      | `EntityAlreadyExists of EntityAlreadyExists.t 
      | `EntityLimitExceeded of EntityLimitExceeded.t 
      | `EntityNotFound of EntityNotFound.t 
      | `InvalidArgument of InvalidArgument.t 
      | `InvalidAssociation of InvalidAssociation.t 
      | `InvalidIfMatchVersion of InvalidIfMatchVersion.t 
      | `PreconditionFailed of PreconditionFailed.t 
      | `Unknown_operation_error of (string * string option) ]
    let make ?distributionTenant =
      fun ?eTag -> fun () -> { distributionTenant; eTag }
    let error_of_json name json =
      match name with
      | "AccessDenied" -> `AccessDenied (AccessDenied.of_json json)
      | "CNAMEAlreadyExists" ->
          `CNAMEAlreadyExists (CNAMEAlreadyExists.of_json json)
      | "EntityAlreadyExists" ->
          `EntityAlreadyExists (EntityAlreadyExists.of_json json)
      | "EntityLimitExceeded" ->
          `EntityLimitExceeded (EntityLimitExceeded.of_json json)
      | "EntityNotFound" -> `EntityNotFound (EntityNotFound.of_json json)
      | "InvalidArgument" -> `InvalidArgument (InvalidArgument.of_json json)
