  struct
    type nonrec t =
      {
      vpcOrigin: VpcOrigin.t option [@ocaml.doc "The VPC origin."];
      location: String_.t option [@ocaml.doc "The VPC origin location."];
      eTag: String_.t option [@ocaml.doc "The VPC origin ETag."]}
    type nonrec error =
      [ `AccessDenied of AccessDenied.t 
      | `EntityAlreadyExists of EntityAlreadyExists.t 
      | `EntityLimitExceeded of EntityLimitExceeded.t 
      | `InconsistentQuantities of InconsistentQuantities.t 
      | `InvalidArgument of InvalidArgument.t 
      | `InvalidTagging of InvalidTagging.t 
      | `UnsupportedOperation of UnsupportedOperation.t 
      | `Unknown_operation_error of (string * string option) ]
    let make ?vpcOrigin =
      fun ?location -> fun ?eTag -> fun () -> { vpcOrigin; location; eTag }
    let error_of_json name json =
      match name with
      | "AccessDenied" -> `AccessDenied (AccessDenied.of_json json)
      | "EntityAlreadyExists" ->
          `EntityAlreadyExists (EntityAlreadyExists.of_json json)
      | "EntityLimitExceeded" ->
          `EntityLimitExceeded (EntityLimitExceeded.of_json json)
      | "InconsistentQuantities" ->
          `InconsistentQuantities (InconsistentQuantities.of_json json)
      | "InvalidArgument" -> `InvalidArgument (InvalidArgument.of_json json)
      | "InvalidTagging" -> `InvalidTagging (InvalidTagging.of_json json)
      | "UnsupportedOperation" ->
          `UnsupportedOperation (UnsupportedOperation.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "AccessDenied" -> `AccessDenied (AccessDenied.of_xml xml)
      | "EntityAlreadyExists" ->
          `EntityAlreadyExists (EntityAlreadyExists.of_xml xml)
      | "EntityLimitExceeded" ->
          `EntityLimitExceeded (EntityLimitExceeded.of_xml xml)
      | "InconsistentQuantities" ->
          `InconsistentQuantities (InconsistentQuantities.of_xml xml)
      | "InvalidArgument" -> `InvalidArgument (InvalidArgument.of_xml xml)
      | "InvalidTagging" -> `InvalidTagging (InvalidTagging.of_xml xml)
      | "UnsupportedOperation" ->
          `UnsupportedOperation (UnsupportedOperation.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `AccessDenied e ->
          `Assoc
            [("error", (`String "AccessDenied"));
            ("details", (AccessDenied.to_json e))]
      | `EntityAlreadyExists e ->
          `Assoc
            [("error", (`String "EntityAlreadyExists"));
            ("details", (EntityAlreadyExists.to_json e))]
      | `EntityLimitExceeded e ->
          `Assoc
            [("error", (`String "EntityLimitExceeded"));
            ("details", (EntityLimitExceeded.to_json e))]
      | `InconsistentQuantities e ->
