module CreateDistributionRequest =
  struct
    type nonrec t =
      {
      distributionConfig: DistributionConfig.t
        [@ocaml.doc "The distribution's configuration information."]}
    let context_ = "CreateDistributionRequest"
    let make ~distributionConfig = fun () -> { distributionConfig }
    let of_header_and_body =
      ((fun (xs, pipe) -> make ~distributionConfig:pipe ())[@warning "-27"])
    let to_value x =
      structure_to_value
        [("DistributionConfig",
           (Some (DistributionConfig.to_value x.distributionConfig)))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let distributionConfig =
        DistributionConfig.of_xml
          (Xml.child_exn ~context:context_ xml_arg0 "DistributionConfig") in
      make ~distributionConfig ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
      let distributionConfig =
        field_map_exn json__ "DistributionConfig" DistributionConfig.of_json in
      make ~distributionConfig ()
    let to_json v = composed_to_json to_value v
  end[@@ocaml.doc "The request to create a new distribution."]
